                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              pg_get_viewdef                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
-----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  SELECT a.app_surface_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
     a.app_surface_name_ja,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
     a.app_category_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
     c.manufacturer_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
     c.manufacturer_name_ja,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
     c.series_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
     c.series_name_ja,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
     c.model_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     c.model_no,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
     c.model_name_ja,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
     c.role_layer_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
     c.role_layer_name_ja,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
     c.model_category_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
     c.app_selection_badge_ja,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
     c.high_function_business_specialized_flag,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
     COALESCE(m.operation_mode_code, s.operation_mode_code, r.operation_mode_code, 'standard'::text) AS operation_mode_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
     GREATEST(COALESCE(a.minimum_self_review_pass_count, 0), COALESCE(m.self_review_pass_count, 0), COALESCE(s.self_review_pass_count, 0), COALESCE(r.self_review_pass_count, 0)) AS self_review_pass_count,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
     GREATEST(COALESCE(a.proposal_count_min, 0), COALESCE(m.proposal_count_min, 0), COALESCE(s.proposal_count_min, 0), COALESCE(r.proposal_count_min, 0)) AS proposal_count_min,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
     GREATEST(COALESCE(a.proposal_count_max, 0), COALESCE(m.proposal_count_max, 0), COALESCE(s.proposal_count_max, 0), COALESCE(r.proposal_count_max, 0)) AS proposal_count_max,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
     COALESCE(m.response_style_code, a.response_style_code, s.response_style_code, r.response_style_code, 'standard'::text) AS response_style_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
     COALESCE(m.required_checklist_code, a.required_checklist_code, s.required_checklist_code, r.required_checklist_code, 'standard_check'::text) AS required_checklist_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
     COALESCE(m.context_scope_code, a.context_scope_code, s.context_scope_code, 'standard_scope'::text) AS context_scope_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
     COALESCE(m.cx_reference_depth_code, a.cx_reference_depth_code, s.cx_reference_depth_code, 'standard'::text) AS cx_reference_depth_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
     COALESCE(m.handoff_format_code, a.handoff_format_code, s.handoff_format_code, 'standard_handoff'::text) AS handoff_format_code,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
     COALESCE(r.handoff_required_flag, false) OR COALESCE(a.review_required_flag, false) AS handoff_required_flag,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     COALESCE(r.review_required_flag, false) OR COALESCE(a.review_required_flag, false) AS review_required_flag,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
     COALESCE(r.human_go_required_flag, false) OR COALESCE(a.human_go_required_flag, false) AS human_go_required_flag,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
     COALESCE(r.external_execution_allowed_flag, false) AND COALESCE(s.external_execution_allowed_flag, false) AND COALESCE(a.external_execution_allowed_flag, false) AS external_execution_allowed_flag,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
     COALESCE(r.pg_apply_allowed_flag, false) AND COALESCE(s.pg_apply_allowed_flag, false) AND COALESCE(a.pg_apply_allowed_flag, false) AS pg_apply_allowed_flag,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
     COALESCE(r.destructive_action_allowed_flag, false) AND COALESCE(s.destructive_action_allowed_flag, false) AND COALESCE(a.destructive_action_allowed_flag, false) AS destructive_action_allowed_flag,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
     ((COALESCE(r.allowed_actions_jsonb, '[]'::jsonb) || COALESCE(s.allowed_actions_jsonb, '[]'::jsonb)) || COALESCE(m.allowed_actions_jsonb, '[]'::jsonb)) || COALESCE(a.allowed_actions_jsonb, '[]'::jsonb) AS allowed_actions_jsonb,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
     ((COALESCE(r.forbidden_actions_jsonb, '[]'::jsonb) || COALESCE(s.forbidden_actions_jsonb, '[]'::jsonb)) || COALESCE(m.forbidden_actions_jsonb, '[]'::jsonb)) || COALESCE(a.forbidden_actions_jsonb, '[]'::jsonb) AS forbidden_actions_jsonb,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
     ((COALESCE(r.prompt_fragment_codes_jsonb, '[]'::jsonb) || COALESCE(s.prompt_fragment_codes_jsonb, '[]'::jsonb)) || COALESCE(m.prompt_fragment_codes_jsonb, '[]'::jsonb)) || COALESCE(a.prompt_fragment_codes_jsonb, '[]'::jsonb) AS prompt_fragment_codes_jsonb,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
     c.capability_card_jsonb,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
     c.model_capability_override_summary_ja,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
     COALESCE(m.model_focus_ja, ''::text) AS model_focus_ja,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
     jsonb_build_object('app_surface_code', a.app_surface_code, 'model_code', c.model_code, 'model_no', c.model_no, 'role_layer_code', c.role_layer_code, 'series_code', c.series_code, 'operation_mode_code', COALESCE(m.operation_mode_code, s.operation_mode_code, r.operation_mode_code, 'standard'::text), 'self_review_pass_count', GREATEST(COALESCE(a.minimum_self_review_pass_count, 0), COALESCE(m.self_review_pass_count, 0), COALESCE(s.self_review_pass_count, 0), COALESCE(r.self_review_pass_count, 0)), 'proposal_count_min', GREATEST(COALESCE(a.proposal_count_min, 0), COALESCE(m.proposal_count_min, 0), COALESCE(s.proposal_count_min, 0), COALESCE(r.proposal_count_min, 0)), 'proposal_count_max', GREATEST(COALESCE(a.proposal_count_max, 0), COALESCE(m.proposal_count_max, 0), COALESCE(s.proposal_count_max, 0), COALESCE(r.proposal_count_max, 0)), 'response_style_code', COALESCE(m.response_style_code, a.response_style_code, s.response_style_code, r.response_style_code, 'standard'::text), 'required_checklist_code', COALESCE(m.required_checklist_code, a.required_checklist_code, s.required_checklist_code, r.required_checklist_code, 'standard_check'::text), 'context_scope_code', COALESCE(m.context_scope_code, a.context_scope_code, s.context_scope_code, 'standard_scope'::text), 'cx_reference_depth_code', COALESCE(m.cx_reference_depth_code, a.cx_reference_depth_code, s.cx_reference_depth_code, 'standard'::text), 'handoff_format_code', COALESCE(m.handoff_format_code, a.handoff_format_code, s.handoff_format_code, 'standard_handoff'::text), 'external_execution_allowed_flag', COALESCE(r.external_execution_allowed_flag, false) AND COALESCE(s.external_execution_allowed_flag, false) AND COALESCE(a.external_execution_allowed_flag, false), 'pg_apply_allowed_flag', COALESCE(r.pg_apply_allowed_flag, false) AND COALESCE(s.pg_apply_allowed_flag, false) AND COALESCE(a.pg_apply_allowed_flag, false), 'destructive_action_allowed_flag', COALESCE(r.destructive_action_allowed_flag, false) AND COALESCE(s.destructive_action_allowed_flag, false) AND COALESCE(a.destructive_action_allowed_flag, false)) AS runtime_control_jsonb,+
     c.sort_order AS model_sort_order,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
     a.sort_order AS app_sort_order                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
    FROM aiworker.app_runtime_control_policy a                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
      CROSS JOIN aiworker.vw_app_aiworker_model_selection_capability_card_v1 c                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
      LEFT JOIN aiworker.role_runtime_control_default r ON r.role_layer_code = c.role_layer_code AND r.status_code = 'active'::text                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
      LEFT JOIN aiworker.series_runtime_control_default s ON s.series_code = c.series_code AND s.status_code = 'active'::text                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
      LEFT JOIN aiworker.model_runtime_control_override m ON m.model_code = c.model_code AND m.status_code = 'active'::text                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   WHERE a.status_code = 'active'::text                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
   ORDER BY a.sort_order, c.sort_order, c.series_code, c.model_no;
(1 row)

